/**
 * Route Helper Functions (Real Road Routing via OSRM)
 */
function calculateDistanceKm(lat1, lon1, lat2, lon2) {
    const R = 6371; // Earth's radius in kilometers
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
}

function distanceToSegmentKm(pLat, pLon, aLat, aLon, bLat, bLon) {
    const dAB = calculateDistanceKm(aLat, aLon, bLat, bLon);
    if (dAB === 0) return calculateDistanceKm(pLat, pLon, aLat, aLon);
    const dAP = calculateDistanceKm(aLat, aLon, pLat, pLon);
    const dx = bLon - aLon;
    const dy = bLat - aLat;
    if (dx === 0 && dy === 0) return dAP;
    let t = ((pLon - aLon) * dx + (pLat - aLat) * dy) / (dx * dx + dy * dy);
    t = Math.max(0.0, Math.min(1.0, t));
    const projLat = aLat + t * dy;
    const projLon = aLon + t * dx;
    return calculateDistanceKm(pLat, pLon, projLat, projLon);
}

function getPlacesAlongRoute(routeWaypoints, locations, maxDistanceKm = 1.5) {
    if (!routeWaypoints || routeWaypoints.length < 2 || !locations) return [];
    const results = [];
    locations.forEach(loc => {
        let minDist = Infinity;
        let nearestSegmentIndex = 0;
        for (let i = 0; i < routeWaypoints.length - 1; i++) {
            const p1 = routeWaypoints[i];
            const p2 = routeWaypoints[i + 1];
            const dist = distanceToSegmentKm(loc.lat, loc.lon, p1.lat, p1.lon, p2.lat, p2.lon);
            if (dist < minDist) {
                minDist = dist;
                nearestSegmentIndex = i;
            }
        }
        if (minDist <= maxDistanceKm) {
            results.push({
                ...loc,
                distanceFromRouteKm: parseFloat(minDist.toFixed(2)),
                nearestSegmentIndex: nearestSegmentIndex
            });
        }
    });
    return results.sort((a, b) => a.distanceFromRouteKm - b.distanceFromRouteKm);
}

function generateRouteStatsReport(routeObj, nearbyPlaces, maxDistanceKm = 1.5) {
    const categoryCounts = {};
    nearbyPlaces.forEach(p => {
        const cat = p.category || 'General';
        categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
    });
    const catSummary = Object.entries(categoryCounts)
        .map(([cat, count]) => `  - ${cat}: ${count}`)
        .join('\n');
    return `GHAZIABAD POLICE ROUTE CORRIDOR INTELLIGENCE REPORT\n` +
           `--------------------------------------------------\n` +
           `Route Name: ${routeObj.name}\n` +
           `Expected Distance: ${routeObj.expectedKm || 'N/A'} km\n` +
           `Buffer Radius: ${maxDistanceKm} km\n` +
           `Official Police Checkpoints/Waypoints: ${routeObj.waypoints ? routeObj.waypoints.length : 0}\n` +
           `Total Places Identified Along Corridor: ${nearbyPlaces.length}\n\n` +
           `Category Breakdown:\n${catSummary || '  - None'}\n` +
           `--------------------------------------------------\n` +
           `Generated by GeoSphere GIS System`;
}

function calculateTotalRouteDistance(locs) {
    const arrayToUse = locs || FLAG_LOCATIONS_DATABASE;
    let totalKm = 0;
    for (let i = 0; i < arrayToUse.length - 1; i++) {
        totalKm += calculateDistanceKm(
            arrayToUse[i].lat, arrayToUse[i].lon,
            arrayToUse[i + 1].lat, arrayToUse[i + 1].lon
        );
    }
    return totalKm.toFixed(2);
}

function getRouteCoordinates(locs) {
    const arrayToUse = locs || FLAG_LOCATIONS_DATABASE;
    return arrayToUse.map(item => [item.lat, item.lon]);
}

/**
 * Fetch real driving road geometry (Google Maps style) using OSRM Public Routing API
 */
async function fetchRealRoadRoute(locs) {
    const arrayToUse = locs || FLAG_LOCATIONS_DATABASE;
    if (arrayToUse.length < 2) return null;

    const waypoints = arrayToUse.map(l => `${l.lon},${l.lat}`).join(';');
    const url = `https://router.project-osrm.org/route/v1/driving/${waypoints}?overview=full&geometries=geojson`;

    try {
        const response = await fetch(url);
        const data = await response.json();

        if (data.code === 'Ok' && data.routes && data.routes.length > 0) {
            const route = data.routes[0];
            const roadLatLngs = route.geometry.coordinates.map(c => [c[1], c[0]]);
            const distanceKm = (route.distance / 1000).toFixed(2);
            const durationMins = Math.round(route.duration / 60);

            return {
                roadLatLngs,
                distanceKm,
                durationMins
            };
        }
    } catch (err) {
        console.warn('OSRM Real Road Routing failed, falling back to straight lines:', err);
    }
    return null;
}

